	const to = escapeString(toOrgId);
	console.log(
		`[migrateOrgSessions] migrating claude_sessions from org=${fromOrgId} to org=${toOrgId}`,
	);
	await ch.execute(
		`ALTER TABLE rudel.claude_sessions UPDATE organization_id = '${to}', ingested_at = now64(3) WHERE organization_id = '${from}'`,
	);
	console.log(
		`[migrateOrgSessions] migrating session_analytics from org=${fromOrgId} to org=${toOrgId}`,
	);
	await ch.execute(
		`ALTER TABLE rudel.session_analytics UPDATE organization_id = '${to}', ingested_at = now64(3) WHERE organization_id = '${from}'`,
	);
	console.log(`[migrateOrgSessions] done`);
}

